import{_ as a,o as t,c as o,ag as l}from"./chunks/framework.C9sp7nFj.js";const n="/screenshots/leave-balance.jpeg",g=JSON.parse('{"title":"Apply for leave","description":"","frontmatter":{},"headers":[],"relativePath":"guide/leave.md","filePath":"guide/leave.md","lastUpdated":1776630283000}'),i={name:"guide/leave.md"};function r(s,e,h,c,u,p){return t(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="apply-for-leave" tabindex="-1">Apply for leave <a class="header-anchor" href="#apply-for-leave" aria-label="Permalink to &quot;Apply for leave&quot;">​</a></h1><p>Request leave, see your balance, and review past applications.</p><h2 id="open-the-leave-hub" tabindex="-1">Open the Leave hub <a class="header-anchor" href="#open-the-leave-hub" aria-label="Permalink to &quot;Open the Leave hub&quot;">​</a></h2><p>Tap the <strong>Leave</strong> tab at the bottom of the screen.</p><figure class="screenshot"><img src="'+n+'" alt="Leave hub showing balance gauges"><figcaption>Leave hub — gauge cards per leave type, &quot;Request a Leave&quot; button, and the latest applications with their status.</figcaption></figure><p>The Leave hub shows, from top to bottom:</p><ol><li><strong>Leave Balance</strong> — gauge cards per leave type (Annual, Sick, Casual, …) with remaining vs total</li><li><strong>&quot;Request a Leave&quot;</strong> — big button to open the application form</li><li><strong>Recent Leaves</strong> — your 5 most recent applications</li><li><strong>Pending Sync</strong> — any requests submitted offline that haven&#39;t synced yet</li></ol><h2 id="request-a-leave" tabindex="-1">Request a leave <a class="header-anchor" href="#request-a-leave" aria-label="Permalink to &quot;Request a leave&quot;">​</a></h2><ol><li>Tap <strong>&quot;Request a Leave&quot;</strong>.</li><li><strong>Leave Type</strong> — pick from the dropdown. Each type shows its remaining balance next to the name.</li><li><strong>Date range</strong> — pick From and To dates. Same day in both for a single-day leave.</li><li><strong>Half day</strong> — tick if this is a half-day leave.</li><li><strong>Reason</strong> — a brief note (optional but usually helpful for HR).</li><li>The <strong>Balance card</strong> shows how many days you have left for the selected type.</li><li>Tap <strong>Submit</strong>.</li></ol><p>You&#39;ll see either:</p><ul><li><strong>&quot;Submitted.&quot;</strong> — when online, directly accepted by the server</li><li><strong>&quot;Queued — will submit when online.&quot;</strong> — when offline, saved locally for sync</li></ul><h2 id="if-the-server-rejects" tabindex="-1">If the server rejects <a class="header-anchor" href="#if-the-server-rejects" aria-label="Permalink to &quot;If the server rejects&quot;">​</a></h2><p>If you apply for more days than your remaining balance, or the dates conflict with another approved leave, the server rejects the request and shows the exact reason — for example:</p><blockquote><p><em>Leave balance exhausted for 2026</em></p></blockquote><p>This happens <strong>only when online</strong>. Offline submissions are trusted at submit time and the validation runs when they reach the server on sync. If a queued leave fails server validation on sync, it shows up in <strong>More → Sync Errors</strong> with the reason.</p><h2 id="viewing-your-leave-history" tabindex="-1">Viewing your leave history <a class="header-anchor" href="#viewing-your-leave-history" aria-label="Permalink to &quot;Viewing your leave history&quot;">​</a></h2><p>Tap <strong>&quot;View Leave History&quot;</strong> at the top of the hub, or <strong>&quot;View List&quot;</strong> below Recent Leaves.</p><p>The list shows every leave application with:</p><ul><li><strong>Leave type</strong> (e.g. Annual Leave)</li><li><strong>Date range</strong> (e.g. <code>15 Jan – 17 Jan · 3d</code>)</li><li><strong>Status badge</strong> — Open / Approved / Rejected / Cancelled</li></ul><h2 id="seeing-one-leave-in-detail" tabindex="-1">Seeing one leave in detail <a class="header-anchor" href="#seeing-one-leave-in-detail" aria-label="Permalink to &quot;Seeing one leave in detail&quot;">​</a></h2><p>Tap any row in Recent Leaves or the full list. A bottom sheet slides up with:</p><ul><li>Leave type</li><li>Period (exact dates)</li><li>Days (including half-day note if applicable)</li><li>Status</li><li>Your reason</li></ul><h3 id="cancelling-a-leave" tabindex="-1">Cancelling a leave <a class="header-anchor" href="#cancelling-a-leave" aria-label="Permalink to &quot;Cancelling a leave&quot;">​</a></h3><p>If the leave is still <strong>Open</strong> (not yet approved or rejected), the sheet shows a red <strong>Cancel</strong> button. Tap it, confirm, and the request is cancelled.</p><p>Once a leave is Approved, Rejected, or Cancelled, you can&#39;t change it from the app — ask HR.</p><h2 id="balance-gauges" tabindex="-1">Balance gauges <a class="header-anchor" href="#balance-gauges" aria-label="Permalink to &quot;Balance gauges&quot;">​</a></h2><p>Each gauge is a half-arc:</p><ul><li>The filled portion shows how much balance you have left</li><li>The number below is <code>balance / total</code> (e.g. <code>15 / 21 days balance</code>)</li><li>Only leave types with an allocation show up — empty types are hidden</li></ul><p>If you see <strong>&quot;No leave allocation yet. Contact HR.&quot;</strong>, your employee record doesn&#39;t have any leave types allocated. HR needs to create a Leave Allocation on the Desk.</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/expense">File an expense claim</a></li><li><a href="/guide/attendance">Attendance calendar</a></li></ul>',31)])])}const v=a(i,[["render",r]]);export{g as __pageData,v as default};
